-- SQL*Plus SHOW command.
-- https://docs.oracle.com/en/database/oracle/oracle-database/latest/sqpug/SHOW.html

SHOW ERRORS;

SHOW ERRORS FUNCTION my_func;

SHOW ERRORS PACKAGE BODY my_pkg;

SHOW PARAMETER;

SHOW PARAMETERS sga_target;

SHOW RECYCLEBIN;

SHOW ALL;

SHOW USER;

SHOW SGA;

SHOW RELEASE;

SHOW PDBS;

SHOW CON_NAME;

SHOW LINESIZE;
